#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <vector>
#include <iostream>
#include <cuda_runtime.h>
#include <sys/time.h>

// Define structures from source
typedef struct {
    float lat;
    float lng;
} LatLong;

typedef struct {
    char recString[49];
    float distance;
} Record;

// CUDA Kernel equivalent to OpenCL NearestNeighbor
__global__ void NearestNeighbor(LatLong *d_locations,
                                float *d_distances,
                                const int numRecords,
                                const float lat,
                                const float lng) {
    int globalId = threadIdx.x + blockIdx.x * blockDim.x;

    if (globalId < numRecords) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        float diffLat = lat - latLong->lat;
        float diffLng = lng - latLong->lng;
        *dist = sqrtf(diffLat * diffLat + diffLng * diffLng);
    }
}

// Helper function to check CUDA errors
void checkCudaError(cudaError_t status, const char *msg, bool exitOnErr) {
    if (status != cudaSuccess) {
        fprintf(stderr, "CUDA Error: %d %s %s\n", status, cudaGetErrorString(status), msg);
        if (exitOnErr) {
            exit(-1);
        }
    }
}

// Memory allocation helper
void* alloc(size_t size) {
    void* ptr = malloc(size);
    if (ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

// Global timing variables
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

char *data_folder = NULL;

// Helper for timeval subtraction
void timersub(struct timeval *end, struct timeval *start, struct timeval *result) {
    result->tv_sec = end->tv_sec - start->tv_sec;
    result->tv_usec = end->tv_usec - start->tv_usec;
    if (result->tv_usec < 0) {
        result->tv_sec--;
        result->tv_usec += 1000000;
    }
}

// Load data function
int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    if (data_folder == NULL) {
        // Default to current directory if not set
        data_folder = (char*)".";
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        exit(0);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            break;
        }
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            if (fgets(record.recString, 49, fp) == NULL) break;
            // consume newline if present
            if (strlen(record.recString) > 0 && record.recString[strlen(record.recString)-1] == '\n') {
                record.recString[strlen(record.recString)-1] = '\0';
            } else {
                // If no newline, maybe we need to read one more char? 
                int c = fgetc(fp);
                if (c == EOF) break;
            }

            char substr[6];
            // Extract lat (positions 28-32)
            for (i = 0; i < 5; i++) {
                if (i + 28 < 49) substr[i] = record.recString[i + 28];
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            // Extract lng (positions 33-37)
            for (i = 0; i < 5; i++) {
                if (i + 33 < 49) substr[i] = record.recString[i + 33];
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

// Find lowest distances (selection sort partial)
void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

// Parse command line arguments
int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    *r = 10; *lat = 0.0; *lng = 0.0; *q = 0; *t = 0; *p = -1; *d = -1;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    if (i < argc) *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        i++;
                        if (i < argc) *lat = atof(argv[i]);
                    } else {
                        i++;
                        if (i < argc) *lng = atof(argv[i]);
                    }
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    if (i < argc) *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    if (i < argc) *d = atoi(argv[i]);
                    break;
                case 'f':
                    i++;
                    if (i < argc) data_folder = argv[i];
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

// Main CUDA implementation of OpenClFindNearestNeighbors
float *CUDAFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat, float lng,
    int timing) {

    LatLong *d_locations;
    float *d_distances;
    float *distances;
    cudaError_t err;

    gettimeofday(&tv_mem_alloc_start, NULL);

    // Allocate device memory
    err = cudaMalloc((void**)&d_locations, sizeof(LatLong) * numRecords);
    checkCudaError(err, "cudaMalloc d_locations", true);

    err = cudaMalloc((void**)&d_distances, sizeof(float) * numRecords);
    checkCudaError(err, "cudaMalloc d_distances", true);

    gettimeofday(&tv_mem_alloc_end, NULL);
    timersub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    // Copy data to device
    gettimeofday(&tv_h2d_start, NULL);
    err = cudaMemcpy(d_locations, &locations[0], sizeof(LatLong) * numRecords, cudaMemcpyHostToDevice);
    checkCudaError(err, "cudaMemcpy locations", true);
    gettimeofday(&tv_h2d_end, NULL);
    timersub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    // Setup kernel launch parameters
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

    gettimeofday(&tv_kernel_start, NULL);

    // Launch kernel
    NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);
    err = cudaDeviceSynchronize();
    checkCudaError(err, "cudaDeviceSynchronize after kernel", true);

    gettimeofday(&tv_kernel_end, NULL);
    timersub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    // Allocate host memory for results
    distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        perror("malloc distances");
        exit(-1);
    }

    gettimeofday(&tv_d2h_start, NULL);
    err = cudaMemcpy(distances, d_distances, sizeof(float) * numRecords, cudaMemcpyDeviceToHost);
    checkCudaError(err, "cudaMemcpy distances", true);
    gettimeofday(&tv_d2h_end, NULL);
    timersub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    gettimeofday(&tv_close_start, NULL);
    cudaFree(d_locations);
    cudaFree(d_distances);
    gettimeofday(&tv_close_end, NULL);
    timersub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    if (timing) {
        printf("# Records\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%d        \t", numRecords);
        printf("%f [%.2fMB]\t", h2d_time / 1000.0, (float)((sizeof(LatLong) * numRecords) / 1e6));
        printf("%f\t", kernel_time / 1000.0);
        printf("%f [%.2fMB]\t", d2h_time / 1000.0, (float)((sizeof(float) * numRecords) / 1e6));
        printf("%f\n\n", (h2d_time + kernel_time + d2h_time) / 1000.0);
    }

    return distances;
}

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances;
    std::vector<LatLong> locations;
    int i;
    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    gettimeofday(&tv_total_start, NULL);

    // CUDA initialization is implicit in runtime API, no explicit context creation needed like OpenCL
    // But we can set device if platform/device logic was intended (CUDA doesn't have platform concept same way)
    if (device >= 0) {
        cudaSetDevice(device);
    }

    gettimeofday(&tv_init_end, NULL);
    timersub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    recordDistances = CUDAFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }

    free(recordDistances);

    gettimeofday(&tv_total_end, NULL);
    timersub(&tv_total_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    if (timing) {
        printf("Init: %f\n", init_time);
        printf("MemAlloc: %f\n", mem_alloc_time);
        printf("HtoD: %f\n", h2d_time);
        printf("Exec: %f\n", kernel_time);
        printf("DtoH: %f\n", d2h_time);
        printf("Close: %f\n", close_time);
        printf("Total: %f\n", total_time);
    }

    return 0;
}
